import com.example.spendroute.ui.theme.SpendRouteTheme
import com.example.spendroute.viewmodel.AddTransactionViewModel
import com.example.spendroute.viewmodel.factory.AddTransactionViewModelFactory
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

enum class TransactionType {
    INCOME, EXPENSE
}

data class CategoryOption(
    val name: String,
    val icon: String,
    val type: TransactionType
)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AddTransactionScreen(
    modifier: Modifier = Modifier,
    onTransactionAdded: () -> Unit = {},
    viewModel: AddTransactionViewModel = viewModel(
        factory = AddTransactionViewModelFactory(
            LocalContext.current.applicationContext as android.app.Application
        )
    )
) {
    // User input states - all empty initially
    val transactionType = remember { mutableStateOf(TransactionType.EXPENSE) }
    val amount = remember { mutableStateOf("") }
    val selectedCategory = remember { mutableStateOf<String?>(null) }
    val note = remember { mutableStateOf("") }
    val selectedDate = remember { mutableStateOf(getCurrentDate()) }

    // Clear form when switching between Income and Expense
    LaunchedEffect(transactionType.value) {
        amount.value = ""
        selectedCategory.value = null
        note.value = ""
        selectedDate.value = getCurrentDate()
    }

    // Date picker state
    val showDatePicker = remember { mutableStateOf(false) }
    val datePickerState = rememberDatePickerState()

    val incomeCategories = listOf(
        CategoryOption("Salary", "", TransactionType.INCOME),
        CategoryOption("Freelance", "", TransactionType.INCOME),
        CategoryOption("Investment", "", TransactionType.INCOME),
        CategoryOption("Gift", "", TransactionType.INCOME),
        CategoryOption("Other", "", TransactionType.INCOME)
    )

    val expenseCategories = listOf(
        CategoryOption("Food", "", TransactionType.EXPENSE),
        CategoryOption("Travel", "", TransactionType.EXPENSE),
        CategoryOption("Bills", "⚡", TransactionType.EXPENSE),
        CategoryOption("Shopping", "️", TransactionType.EXPENSE),
        CategoryOption("Other", "", TransactionType.EXPENSE)
    )

    val categories = if (transactionType.value == TransactionType.INCOME) incomeCategories else expenseCategories
    //val headerColor = if (transactionType.value == TransactionType.INCOME) Color(0xFF4CAF50) else Color(0xFFE53935)
    //val underlineColor = if (transactionType.value == TransactionType.INCOME) Color(0xFF4CAF50) else Color(0xFFE53935)
    val buttonText = if (transactionType.value == TransactionType.INCOME) "Save income" else "Save expense"

    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFFF8F7FC))
    ) {
        // Fixed Purple Header - stays at top while scrolling
        GreetingHeader(
            title = if (transactionType.value == TransactionType.INCOME) "Add income" else "Add expense",
            subtitle = if (transactionType.value == TransactionType.INCOME) "Record your earnings" else "Record your spending",
            //headerBackgroundColor = Color(0xFF5B4B9B),
            showAvatar = false
        )

        // Scrollable content
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFFF8F7FC))
        ) {

        // Income/Expense Switch
        item {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 12.dp),
                horizontalArrangement = Arrangement.Center
            ) {
                SingleChoiceSegmentedButtonRow(
                    modifier = Modifier.fillMaxWidth()
                ) {
                    SegmentedButton(
                        selected = transactionType.value == TransactionType.EXPENSE,
                        onClick = { transactionType.value = TransactionType.EXPENSE },
                        shape = RoundedCornerShape(
                            topStart = 8.dp,
                            bottomStart = 8.dp,
                            topEnd = 0.dp,
                            bottomEnd = 0.dp
                        ),
                        modifier = Modifier.weight(1f),
                        icon = { }
                    ) {
                        Text("- Expense")
                    }
                    SegmentedButton(
                        selected = transactionType.value == TransactionType.INCOME,
                        onClick = { transactionType.value = TransactionType.INCOME },
                        shape = RoundedCornerShape(
                            topStart = 0.dp,
                            bottomStart = 0.dp,
                            topEnd = 8.dp,
                            bottomEnd = 8.dp
                        ),
                        modifier = Modifier.weight(1f),
                        icon = { }
                    ) {
                        Text("+ Income")
                    }
                }
            }
        }

        // Amount Input Card
        item {
            ElevatedCard(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 12.dp),
                colors = CardDefaults.elevatedCardColors(containerColor = Color.White)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp)
                ) {
                    Text(
                        text = "Amount",
                        style = LocalTypography.current.bodySmallNormal,
                        color = Color.DarkGray
                    )
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Text(
                            text = "Rs.",
                            style = LocalTypography.current.bodyMediumPrimary,
                            color = Color.Black,
                            //color = if (transactionType.value == TransactionType.INCOME) Color(0xFF4CAF50) else Color(0xFFE53935),
                            fontSize = 36.sp
                        )
                        TextField(
                            value = amount.value,
                            onValueChange = { amount.value = it },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number, imeAction = ImeAction.Next),
                            modifier = Modifier
                                .weight(1f)
                                .background(Color.Transparent),
                            placeholder = {
                                Text(
                                    text = "Enter amount",
                                    style = LocalTypography.current.bodyExtraLargeText.copy(
                                        fontSize = 36.sp,
                                        fontWeight = FontWeight.Bold
                                    ),
                                    color = Color(0xFFBDBDBD)
                                )
                            },
                            textStyle = LocalTypography.current.bodyExtraLargeText.copy(
                                fontSize = 36.sp,
                                fontWeight = FontWeight.Bold
                            ),
                            colors = TextFieldDefaults.colors(
                                focusedContainerColor = Color.Transparent,
                                unfocusedContainerColor = Color.Transparent,
                                focusedIndicatorColor = Color.Transparent,
                                unfocusedIndicatorColor = Color.Transparent
                            ),
                            singleLine = true
                        )
                    }
                }
            }
        }

        // Category Selection Card
        item {
            ElevatedCard(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 12.dp),
                colors = CardDefaults.elevatedCardColors(containerColor = Color.White)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp)
                ) {
                    Text(
                        text = "Source",
                        style = LocalTypography.current.bodySmallNormal,
                        color = Color.DarkGray
                    )
                    LazyRow(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(top = 12.dp),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        items(categories) { category ->
                            ElevatedCard(
                                modifier = Modifier
                                    .border(
                                        width = if (selectedCategory.value == category.name) 2.dp else 0.dp,
                                        color = if (selectedCategory.value == category.name) Color(0xFF4DB8A8) else Color.Transparent,
                                        shape = RoundedCornerShape(12.dp)
                                    )
                                    .clickable { selectedCategory.value = category.name },
                                colors = CardDefaults.elevatedCardColors(
                                    containerColor = if (selectedCategory.value == category.name) Color(0xFFE0F7F6) else Color(0xFFF5F5F5)
                                )
                            ) {
                                Column(
                                    modifier = Modifier.padding(12.dp),
                                    horizontalAlignment = Alignment.CenterHorizontally,
                                    verticalArrangement = Arrangement.spacedBy(4.dp)
                                ) {
                                    Text(
                                        text = category.icon,
                                        fontSize = 24.sp
                                    )
                                    Text(
                                        text = category.name,
                                        style = LocalTypography.current.bodySmallNormal,
                                        color = Color(0xFF5B4B9B),
                                        fontSize = 12.sp,
                                        textAlign = TextAlign.Center
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // Note (Optional) Card
        item {
            val notePlaceholder = if (transactionType.value == TransactionType.INCOME) 
                "e.g. Freelance project" 
            else 
                "e.g. Dinner with friends"

            ElevatedCard(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 12.dp),
                colors = CardDefaults.elevatedCardColors(containerColor = Color.White)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp)
                ) {
                    Text(
                        text = "Note (optional)",
                        style = LocalTypography.current.bodySmallNormal,
                        color = Color.DarkGray
                    )
                    TextField(
                        value = note.value,
                        onValueChange = { note.value = it },
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(Color.Transparent),
                        placeholder = {
                            Text(
                                text = notePlaceholder,
                                style = LocalTypography.current.bodyMediumRegular,
                                color = Color(0xFFBDBDBD)
                            )
                        },
                        colors = TextFieldDefaults.colors(
                            focusedContainerColor = Color.Transparent,
                            unfocusedContainerColor = Color.Transparent
                        ),
                        singleLine = true
                    )
                }
            }
        }

        // Date Card with DatePicker Dialog
        item {
            // Show DatePickerDialog when showDatePicker is true
            if (showDatePicker.value) {
                DatePickerDialog(
                    onDismissRequest = { showDatePicker.value = false },
                    confirmButton = {
                        TextButton(
                            onClick = {
                                datePickerState.selectedDateMillis?.let { millis ->
                                    val date = Date(millis)
                                    val dateFormat = SimpleDateFormat("MMM d, yyyy", Locale.getDefault())
                                    selectedDate.value = dateFormat.format(date)
                                }
                                showDatePicker.value = false
                            }
                        ) {
                            Text("OK")
                        }
                    },
                    dismissButton = {
                        TextButton(onClick = { showDatePicker.value = false }) {
                            Text("Cancel")
                        }
                    }
                ) {
                    DatePicker(state = datePickerState)
                }
            }

            ElevatedCard(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 12.dp)
                    .clickable { showDatePicker.value = true },
                colors = CardDefaults.elevatedCardColors(containerColor = Color.White)
            ) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "Date",
                        style = LocalTypography.current.bodySmallNormal,
                        color = Color.DarkGray
                    )
                    Text(
                        text = selectedDate.value,
                        style = LocalTypography.current.bodyMediumPrimary,
                        color = Color(0xFF5B4B9B)
                    )
                }
            }
        }

        // Save Button
        item {
            Button(
                onClick = {
                    // Validate inputs
                    if (amount.value.isNotEmpty() && 
                        selectedCategory.value != null &&
                        amount.value.toDoubleOrNull() != null &&
                        amount.value.toDouble() > 0
                    ) {
                        viewModel.addTransaction(
                            title = selectedCategory.value!!, // Use category as title
                            category = selectedCategory.value!!,
                            amount = amount.value.toDouble(),
                            date = selectedDate.value, // Use selected date from date picker
                            time = getCurrentTime(),
                            note = note.value,
                            isIncome = transactionType.value == TransactionType.INCOME
                        )
                        // Clear form
                        amount.value = ""
                        selectedCategory.value = null
                        note.value = ""
                        onTransactionAdded()
                    }
                },
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 20.dp)
                    .height(50.dp),
                colors = ButtonDefaults.buttonColors(
                    containerColor = Color(0xFF5B4B9B),
                    disabledContainerColor = Color(0xFFB8B3E5)
                ),
                shape = RoundedCornerShape(12.dp),
                enabled = amount.value.isNotEmpty() && selectedCategory.value != null
            ) {
                Text(
                    text = buttonText,
                    style = LocalTypography.current.headingSmallSemibold,
                    color = Color.White
                )
            }
        }

        // Bottom spacing for navigation bar
        item {
            Box(modifier = Modifier.height(80.dp))
        }
    }
    }
}

