private fun getCurrentDate(): String {
    val dateFormat = SimpleDateFormat("MMM d", Locale.getDefault())
    return "Today, ${dateFormat.format(Date())}"
}

private fun getCurrentTime(): String {
    val timeFormat = SimpleDateFormat("h:mm a", Locale.getDefault())
    return timeFormat.format(Date())
}

package com.example.spendroute.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.spendroute.data.model.Transaction
import com.example.spendroute.database.SpendRouteDatabase
import com.example.spendroute.repository.TransactionRepository
import kotlinx.coroutines.launch

class AddTransactionViewModel(application: Application) : AndroidViewModel(application) {

    private val database = SpendRouteDatabase.getDatabase(application)
    private val repository = TransactionRepository(database.transactionDao())

    fun addTransaction(
        title: String,
        category: String,
        amount: Double,
        date: String,
        time: String,
        note: String,
        isIncome: Boolean
    ) {
        if (title.isEmpty() || amount <= 0) {
            return
        }

        val transaction = Transaction(
            id = System.currentTimeMillis().toString(),
            title = title,
            category = category,
            amount = amount,
            date = date,
            time = time,
            isIncome = isIncome
        )

        viewModelScope.launch {
            repository.insertTransaction(transaction)
        }
    }
}

package com.example.spendroute.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.spendroute.data.model.Transaction
import com.example.spendroute.database.SpendRouteDatabase
import com.example.spendroute.repository.TransactionRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

class AddTransactionViewModel(application: Application) : AndroidViewModel(application) {

    private val database = SpendRouteDatabase.getDatabase(application)
    private val repository = TransactionRepository(database.transactionDao())

    private val _transactionToEdit = MutableStateFlow<Transaction?>(null)
    val transactionToEdit: StateFlow<Transaction?> = _transactionToEdit.asStateFlow()

    fun setTransactionToEdit(transaction: Transaction?) {
        _transactionToEdit.value = transaction
    }

    fun addTransaction(
        title: String,
        category: String,
        amount: Double,
        date: String,
        time: String,
        note: String,
        isIncome: Boolean
    ) {
        if (title.isEmpty() || amount <= 0) {
            return
        }

        val transaction = Transaction(
            id = System.currentTimeMillis().toString(),
            title = title,
            category = category,
            amount = amount,
            date = date,
            time = time,
            isIncome = isIncome
        )

        viewModelScope.launch {
            repository.insertTransaction(transaction)
        }
    }

    fun updateTransaction(
        id: String,
        title: String,
        category: String,
        amount: Double,
        date: String,
        time: String,
        note: String,
        isIncome: Boolean
    ) {
        if (title.isEmpty() || amount <= 0) {
            return
        }

        val transaction = Transaction(
            id = id,
            title = title,
            category = category,
            amount = amount,
            date = date,
            time = time,
            isIncome = isIncome
        )

        viewModelScope.launch {
            repository.updateTransaction(transaction)
        }
    }
}

