@Composable
fun AnalyticsScreen(
    modifier: Modifier = Modifier,
    viewModel: AnalyticsViewModel = viewModel(
        factory = AnalyticsViewModelFactory(
            LocalContext.current.applicationContext as android.app.Application
        )
    )
) {
    val analyticsData = viewModel.analyticsData.collectAsState()
    val selectedPeriod = viewModel.selectedPeriod.collectAsState()

    // Get current month and year
    val calendar = Calendar.getInstance()
    val monthName = SimpleDateFormat("MMMM", Locale.getDefault()).format(calendar.time)
    val year = calendar.get(Calendar.YEAR)

    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFFF8F7FC))
    ) {
        // Fixed Header
        GreetingHeader(
            title = "Analytics",
            subtitle = "$monthName $year",
            showAvatar = false
        )

        // Scrollable content
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFFF8F7FC))
        ) {
            // Period Selection Buttons
            item {
                PeriodToggleButtons(
                    selectedPeriod = selectedPeriod.value,
                    onPeriodSelected = { period ->
                        viewModel.selectPeriod(period)
                    }
                )
            }

            // Summary Cards Row
            item {
                SummaryCardsRow(
                    totalIncome = analyticsData.value.totalIncome,
                    totalExpense = analyticsData.value.totalExpense,
                    incomeChangePercent = analyticsData.value.incomeChangePercent,
                    expenseChangePercent = analyticsData.value.expenseChangePercent
                )
            }

            // Income vs Expense Chart
            item {
                IncomeVsExpenseChart(
                    monthlyData = analyticsData.value.monthlyData
                )
            }

            // Expense by Category
            item {
                ExpenseByCategorySection(
                    categoryExpenses = analyticsData.value.categoryExpenses,
                    totalExpense = analyticsData.value.totalExpense
                )
            }

            item {
                Spacer(modifier = Modifier.height(16.dp))
            }
        }
    }
}

@Composable
private fun PeriodToggleButtons(
    selectedPeriod: String,
    onPeriodSelected: (String) -> Unit,
    modifier: Modifier = Modifier
) {
    Row(
        modifier = modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 16.dp),
        horizontalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        listOf("Monthly", "Weekly", "Yearly").forEach { period ->
            val isSelected = period == selectedPeriod
            ElevatedCard(
                modifier = Modifier
                    .weight(1f)
                    .clickable { onPeriodSelected(period) },
                colors = CardDefaults.elevatedCardColors(
                    containerColor = if (isSelected) Color(0xFF7C6FD4) else Color.White
                ),
                shape = RoundedCornerShape(12.dp)
            ) {
                Text(
                    text = period,
                    style = LocalTypography.current.bodySmallNormal,
                    color = if (isSelected) Color.White else Color(0xFF7C6FD4),
                    modifier = Modifier
                        .align(Alignment.CenterHorizontally)
                        .padding(vertical = 10.dp)
                )
            }
        }
    }
}

@Composable
private fun SummaryCardsRow(
    totalIncome: Double,
    totalExpense: Double,
    incomeChangePercent: Float,
    expenseChangePercent: Float,
    modifier: Modifier = Modifier
) {
    Row(
        modifier = modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 8.dp),
        horizontalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        // Income Card
        SummaryCard(
            modifier = Modifier.weight(1f),
            title = "Total income",
            amount = totalIncome,
            changePercent = incomeChangePercent,
            backgroundColor = Color(0xFFDEF3D8),
            textColor = Color(0xFF2D5C4F)
        )

        // Expense Card
        SummaryCard(
            modifier = Modifier.weight(1f),
            title = "Total expense",
            amount = totalExpense,
            changePercent = expenseChangePercent,
            backgroundColor = Color(0xFFFDEDED),
            textColor = Color(0xFF5C3B4F)
        )
    }
}

@Composable
private fun SummaryCard(
    title: String,
    amount: Double,
    changePercent: Float,
    backgroundColor: Color,
    textColor: Color,
    modifier: Modifier = Modifier
) {
    ElevatedCard(
        modifier = modifier,
        colors = CardDefaults.elevatedCardColors(containerColor = backgroundColor),
        shape = RoundedCornerShape(16.dp)
    ) {
        Column(
            modifier = Modifier.padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Text(
                text = title,
                style = LocalTypography.current.bodySmallNormal,
                color = textColor,
                fontSize = 12.sp
            )

            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                Text(
                    text = "Rs. ${String.format(Locale.US, "%.0f", amount).replace(".0", "")}",
                    style = LocalTypography.current.bodyLargeSemibold,
                    color = textColor,
                    fontSize = 18.sp
                )
            }

            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                val changeText = if (changePercent >= 0) {
                    "+${String.format(Locale.US, "%.0f", changePercent)}%"
                } else {
                    "${String.format(Locale.US, "%.0f", changePercent)}%"
                }
                val changeColor = if (changePercent >= 0) Color(0xFF4CAF50) else Color(0xFFE53935)

                Text(
                    text = changeText,
                    style = LocalTypography.current.bodySmallNormal,
                    color = changeColor,
                    fontSize = 10.sp
                )

                Text(
                    text = "vs last month",
                    style = LocalTypography.current.bodySmallNormal,
                    color = textColor,
                    fontSize = 10.sp
                )
            }
        }
    }
}

@Composable
private fun IncomeVsExpenseChart(
    monthlyData: List<com.example.spendroute.viewmodel.MonthlyChartData>,
    modifier: Modifier = Modifier
) {
    if (monthlyData.isEmpty()) {
        return
    }

    Column(
        modifier = modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 16.dp)
    ) {
        Text(
            text = "Income vs Expense",
            style = LocalTypography.current.bodyLargeSemibold,
            color = Color.Black,
            modifier = Modifier.padding(bottom = 8.dp)
        )

        Text(
            text = "Last 6 months",
            style = LocalTypography.current.bodySmallNormal,
            color = Color(0xFF999999),
            fontSize = 12.sp,
            modifier = Modifier.padding(bottom = 16.dp)
        )

        val maxValue = monthlyData.maxOf { maxOf(it.income, it.expense) }
        val scale = 200f / maxValue.coerceAtLeast(1.0).toFloat()

        Column(
            modifier = Modifier
                .fillMaxWidth()
                .height(250.dp)
                .padding(vertical = 16.dp)
        ) {
            Row(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(4.dp),
                verticalAlignment = Alignment.Bottom
            ) {
                monthlyData.forEach { monthData ->
                    Column(
                        modifier = Modifier
                            .weight(1f)
                            .height(200.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(4.dp, Alignment.Bottom)
                    ) {
                        Spacer(
                            modifier = Modifier
                                .width(16.dp)
                                .height((monthData.income * scale).dp)
                                .background(Color(0xFF4ECDC4), RoundedCornerShape(topStart = 4.dp, topEnd = 4.dp))
                        )

                        Spacer(
                            modifier = Modifier
                                .width(16.dp)
                                .height((monthData.expense * scale).dp)
                                .background(Color(0xFF7C6FD4), RoundedCornerShape(topStart = 4.dp, topEnd = 4.dp))
                        )
                    }
                }
            }

            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(top = 8.dp),
                horizontalArrangement = Arrangement.spacedBy(4.dp)
            ) {
                monthlyData.forEach { monthData ->
                    Text(
                        text = monthData.month,
                        style = LocalTypography.current.bodySmallNormal,
                        color = Color(0xFF999999),
                        fontSize = 10.sp,
                        modifier = Modifier
                            .weight(1f)
                            .align(Alignment.CenterVertically),
                        textAlign = TextAlign.Center
                    )
                }
            }
        }

        // Legend
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(top = 12.dp),
            horizontalArrangement = Arrangement.Center,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Row(
                modifier = Modifier.padding(end = 24.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(6.dp)
            ) {
                Spacer(
                    modifier = Modifier
                        .width(12.dp)
                        .height(12.dp)
                        .background(Color(0xFF4ECDC4), RoundedCornerShape(2.dp))
                )
                Text(
                    text = "Income",
                    style = LocalTypography.current.bodySmallNormal,
                    color = Color.Black,
                    fontSize = 11.sp
                )
            }

            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(6.dp)
            ) {
                Spacer(
                    modifier = Modifier
                        .width(12.dp)
                        .height(12.dp)
                        .background(Color(0xFF7C6FD4), RoundedCornerShape(2.dp))
                )
                Text(
                    text = "Expense",
                    style = LocalTypography.current.bodySmallNormal,
                    color = Color.Black,
                    fontSize = 11.sp
                )
            }
        }
    }
}

@Composable
private fun ExpenseByCategorySection(
    categoryExpenses: List<com.example.spendroute.data.model.CategoryExpense>,
    totalExpense: Double,
    modifier: Modifier = Modifier
) {
    Column(
        modifier = modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 16.dp)
    ) {
        Text(
            text = "Expense by category",
            style = LocalTypography.current.bodyLargeSemibold,
            color = Color.Black,
            modifier = Modifier.padding(bottom = 12.dp)
        )

        if (categoryExpenses.isEmpty()) {
            Text(
                text = "No expenses yet",
                style = LocalTypography.current.bodySmallNormal,
                color = Color(0xFF999999),
                modifier = Modifier.padding(vertical = 16.dp)
            )
        } else {
            categoryExpenses.forEach { category ->
                ExpenseCategoryItem(
                    name = category.name,
                    amount = category.amount,
                    percentage = if (totalExpense > 0) (category.amount / totalExpense * 100).toFloat() else 0f
                )
            }
        }
    }
}

@Composable
private fun ExpenseCategoryItem(
    name: String,
    amount: Double,
    percentage: Float,
    modifier: Modifier = Modifier
) {
    Column(
        modifier = modifier
            .fillMaxWidth()
            .padding(vertical = 8.dp)
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(bottom = 6.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                text = name,
                style = LocalTypography.current.bodySmallNormal,
                color = Color.Black,
                fontSize = 14.sp
            )

            Row(
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = "Rs. ${String.format(Locale.US, "%.0f", amount).replace(".0", "")}",
                    style = LocalTypography.current.bodySmallNormal,
                    color = Color.Black,
                    fontSize = 12.sp
                )

                Text(
                    text = "- ${String.format(Locale.US, "%.0f", percentage)}%",
                    style = LocalTypography.current.bodySmallNormal,
                    color = Color(0xFF999999),
                    fontSize = 12.sp
                )
            }
        }

        // Progress bar
        ElevatedCard(
            modifier = Modifier
                .fillMaxWidth()
                .height(8.dp),
            colors = CardDefaults.elevatedCardColors(
                containerColor = Color(0xFFE8E8E8)
            ),
            shape = RoundedCornerShape(4.dp)
        ) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Color(0xFF4ECDC4))
            ) {
                Spacer(
                    modifier = Modifier
                        .fillMaxWidth(percentage / 100f)
                        .height(8.dp)
                        .background(
                            when {
                                percentage > 30 -> Color(0xFF7C6FD4)
                                percentage > 20 -> Color(0xFF4ECDC4)
                                else -> Color(0xFF4CAF50)
                            }
                        )
                )
            }
        }
    }
}

