package com.example.spendroute.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.spendroute.data.model.CategoryExpense
import com.example.spendroute.data.model.Transaction
import com.example.spendroute.database.SpendRouteDatabase
import com.example.spendroute.repository.TransactionRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import java.text.SimpleDateFormat
import java.util.Calendar
import java.util.Locale

data class AnalyticsData(
    val totalIncome: Double = 0.0,
    val totalExpense: Double = 0.0,
    val incomeChangePercent: Float = 0f,
    val expenseChangePercent: Float = 0f,
    val monthlyData: List<MonthlyChartData> = emptyList(),
    val categoryExpenses: List<CategoryExpense> = emptyList()
)

data class MonthlyChartData(
    val month: String,
    val income: Double,
    val expense: Double
)

class AnalyticsViewModel(application: Application) : AndroidViewModel(application) {

    private val database = SpendRouteDatabase.getDatabase(application)
    private val repository = TransactionRepository(database.transactionDao())

    private val _analyticsData = MutableStateFlow<AnalyticsData>(AnalyticsData())
    val analyticsData: StateFlow<AnalyticsData> = _analyticsData.asStateFlow()

    private val _selectedPeriod = MutableStateFlow("Monthly")
    val selectedPeriod: StateFlow<String> = _selectedPeriod.asStateFlow()

    init {
        loadAnalyticsData()
    }

    fun selectPeriod(period: String) {
        _selectedPeriod.value = period
        loadAnalyticsData()
    }

    private fun loadAnalyticsData() {
        viewModelScope.launch {
            repository.getAllTransactions().collect { transactions ->
                when (_selectedPeriod.value) {
                    "Weekly" -> loadWeeklyData(transactions)
                    "Yearly" -> loadYearlyData(transactions)
                    else -> loadMonthlyData(transactions) // Monthly is default
                }
            }
        }
    }

    private fun loadMonthlyData(transactions: List<Transaction>) {
        // Get current month and last month
        val calendar = Calendar.getInstance()
        val currentMonth = calendar.get(Calendar.MONTH) + 1
        val currentYear = calendar.get(Calendar.YEAR)

        // Calculate current month data
        val currentMonthTransactions = transactions.filter { transaction ->
            val transactionMonth = getMonthFromDate(transaction.date)
            val transactionYear = getYearFromDate(transaction.date)
            transactionMonth == currentMonth && transactionYear == currentYear
        }

        val currentIncome = currentMonthTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val currentExpense = currentMonthTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate last month data for comparison
        val lastMonthDate = Calendar.getInstance().apply { add(Calendar.MONTH, -1) }
        val lastMonth = lastMonthDate.get(Calendar.MONTH) + 1
        val lastYear = lastMonthDate.get(Calendar.YEAR)

        val lastMonthTransactions = transactions.filter { transaction ->
            val transactionMonth = getMonthFromDate(transaction.date)
            val transactionYear = getYearFromDate(transaction.date)
            transactionMonth == lastMonth && transactionYear == lastYear
        }

        val lastIncome = lastMonthTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val lastExpense = lastMonthTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate percentage changes
        val incomeChangePercent = if (lastIncome > 0) {
            ((currentIncome - lastIncome) / lastIncome * 100).toFloat()
        } else {
            0f
        }

        val expenseChangePercent = if (lastExpense > 0) {
            ((currentExpense - lastExpense) / lastExpense * 100).toFloat()
        } else {
            0f
        }

        // Get last 6 months data for chart
        val last6MonthsData = mutableListOf<MonthlyChartData>()
        for (i in 5 downTo 0) {
            val monthCalendar = Calendar.getInstance().apply { add(Calendar.MONTH, -i) }
            val month = monthCalendar.get(Calendar.MONTH) + 1
            val year = monthCalendar.get(Calendar.YEAR)
            val monthName = getMonthName(month)

            val monthTransactions = transactions.filter { transaction ->
                val transactionMonth = getMonthFromDate(transaction.date)
                val transactionYear = getYearFromDate(transaction.date)
                transactionMonth == month && transactionYear == year
            }

            val monthIncome = monthTransactions.filter { it.isIncome }.sumOf { it.amount }
            val monthExpense = monthTransactions.filter { !it.isIncome }.sumOf { it.amount }

            last6MonthsData.add(
                MonthlyChartData(
                    month = monthName.take(3),
                    income = monthIncome,
                    expense = monthExpense
                )
            )
        }

        // Calculate category expenses
        val categoryMap = mutableMapOf<String, Double>()
        currentMonthTransactions.filter { !it.isIncome }.forEach { transaction ->
            val current = categoryMap[transaction.category] ?: 0.0
            categoryMap[transaction.category] = current + transaction.amount
        }

        val categoryExpenses = categoryMap.map { (category, amount) ->
            CategoryExpense(name = category, amount = amount)
        }.sortedByDescending { it.amount }

        _analyticsData.value = AnalyticsData(
            totalIncome = currentIncome,
            totalExpense = currentExpense,
            incomeChangePercent = incomeChangePercent,
            expenseChangePercent = expenseChangePercent,
            monthlyData = last6MonthsData,
            categoryExpenses = categoryExpenses
        )
    }

    private fun loadWeeklyData(transactions: List<Transaction>) {
        // Get current week start (6 days ago) and current date
        val calendar = Calendar.getInstance()
        val today = calendar.clone() as Calendar

        val weekStartCalendar = Calendar.getInstance()
        weekStartCalendar.add(Calendar.DAY_OF_YEAR, -6)

        val lastWeekStartCalendar = Calendar.getInstance()
        lastWeekStartCalendar.add(Calendar.DAY_OF_YEAR, -13)

        val lastWeekEndCalendar = Calendar.getInstance()
        lastWeekEndCalendar.add(Calendar.DAY_OF_YEAR, -7)

        // Helper function to check if date is between two dates (ignoring time)
        fun isDateInRange(dateString: String, startCalendar: Calendar, endCalendar: Calendar): Boolean {
            val month = getMonthFromDate(dateString)
            val year = getYearFromDate(dateString)
            val day = getDayFromDate(dateString)

            if (month == 0 || year == 0 || day == 0) return false

            val dateToCheck = Calendar.getInstance()
            dateToCheck.set(year, month - 1, day)

            val startDate = Calendar.getInstance()
            startDate.set(startCalendar.get(Calendar.YEAR), startCalendar.get(Calendar.MONTH), startCalendar.get(Calendar.DAY_OF_MONTH))

            val endDate = Calendar.getInstance()
            endDate.set(endCalendar.get(Calendar.YEAR), endCalendar.get(Calendar.MONTH), endCalendar.get(Calendar.DAY_OF_MONTH))

            return dateToCheck.timeInMillis >= startDate.timeInMillis && dateToCheck.timeInMillis <= endDate.timeInMillis
        }

        // Filter current week transactions
        val currentWeekTransactions = transactions.filter { transaction ->
            isDateInRange(transaction.date, weekStartCalendar, today)
        }

        val currentIncome = currentWeekTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val currentExpense = currentWeekTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Filter last week transactions
        val lastWeekTransactions = transactions.filter { transaction ->
            isDateInRange(transaction.date, lastWeekStartCalendar, lastWeekEndCalendar)
        }

        val lastIncome = lastWeekTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val lastExpense = lastWeekTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate percentage changes
        val incomeChangePercent = if (lastIncome > 0) {
            ((currentIncome - lastIncome) / lastIncome * 100).toFloat()
        } else {
            0f
        }

        val expenseChangePercent = if (lastExpense > 0) {
            ((currentExpense - lastExpense) / lastExpense * 100).toFloat()
        } else {
            0f
        }

        // Get last 6 weeks data for chart
        val last6WeeksData = mutableListOf<MonthlyChartData>()
        for (i in 5 downTo 0) {
            val weekCalendar = Calendar.getInstance()
            weekCalendar.add(Calendar.WEEK_OF_YEAR, -i)

            val weekStartDay = weekCalendar.clone() as Calendar
            weekStartDay.set(Calendar.DAY_OF_WEEK, Calendar.MONDAY)

            val weekEndDay = weekCalendar.clone() as Calendar
            weekEndDay.set(Calendar.DAY_OF_WEEK, Calendar.SUNDAY)

            val weekTransactions = transactions.filter { transaction ->
                isDateInRange(transaction.date, weekStartDay, weekEndDay)
            }

            val weekIncome = weekTransactions.filter { it.isIncome }.sumOf { it.amount }
            val weekExpense = weekTransactions.filter { !it.isIncome }.sumOf { it.amount }

            val weekLabel = "W${weekCalendar.get(Calendar.WEEK_OF_YEAR)}"
            last6WeeksData.add(
                MonthlyChartData(
                    month = weekLabel,
                    income = weekIncome,
                    expense = weekExpense
                )
            )
        }

        // Calculate category expenses for current week
        val categoryMap = mutableMapOf<String, Double>()
        currentWeekTransactions.filter { !it.isIncome }.forEach { transaction ->
            val current = categoryMap[transaction.category] ?: 0.0
            categoryMap[transaction.category] = current + transaction.amount
        }

        val categoryExpenses = categoryMap.map { (category, amount) ->
            CategoryExpense(name = category, amount = amount)
        }.sortedByDescending { it.amount }

        _analyticsData.value = AnalyticsData(
            totalIncome = currentIncome,
            totalExpense = currentExpense,
            incomeChangePercent = incomeChangePercent,
            expenseChangePercent = expenseChangePercent,
            monthlyData = last6WeeksData,
            categoryExpenses = categoryExpenses
        )
    }

    private fun loadYearlyData(transactions: List<Transaction>) {
        // Get current year and last year
        val calendar = Calendar.getInstance()
        val currentYear = calendar.get(Calendar.YEAR)
        val lastYear = currentYear - 1

        // Calculate current year data
        val currentYearTransactions = transactions.filter { transaction ->
            val transactionYear = getYearFromDate(transaction.date)
            transactionYear == currentYear
        }

        val currentIncome = currentYearTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val currentExpense = currentYearTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate last year data for comparison
        val lastYearTransactions = transactions.filter { transaction ->
            val transactionYear = getYearFromDate(transaction.date)
            transactionYear == lastYear
        }

        val lastIncome = lastYearTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val lastExpense = lastYearTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate percentage changes
        val incomeChangePercent = if (lastIncome > 0) {
            ((currentIncome - lastIncome) / lastIncome * 100).toFloat()
        } else {
            0f
        }

        val expenseChangePercent = if (lastExpense > 0) {
            ((currentExpense - lastExpense) / lastExpense * 100).toFloat()
        } else {
            0f
        }

        // Get last 6 months data within current year for chart
        val last6MonthsData = mutableListOf<MonthlyChartData>()
        for (i in 5 downTo 0) {
            val monthCalendar = Calendar.getInstance().apply { add(Calendar.MONTH, -i) }
            val month = monthCalendar.get(Calendar.MONTH) + 1
            val year = monthCalendar.get(Calendar.YEAR)
            val monthName = getMonthName(month)

            val monthTransactions = transactions.filter { transaction ->
                val transactionMonth = getMonthFromDate(transaction.date)
                val transactionYear = getYearFromDate(transaction.date)
                transactionMonth == month && transactionYear == year
            }

            val monthIncome = monthTransactions.filter { it.isIncome }.sumOf { it.amount }
            val monthExpense = monthTransactions.filter { !it.isIncome }.sumOf { it.amount }

            last6MonthsData.add(
                MonthlyChartData(
                    month = monthName.take(3),
                    income = monthIncome,
                    expense = monthExpense
                )
            )
        }

        // Calculate category expenses for current year
        val categoryMap = mutableMapOf<String, Double>()
        currentYearTransactions.filter { !it.isIncome }.forEach { transaction ->
            val current = categoryMap[transaction.category] ?: 0.0
            categoryMap[transaction.category] = current + transaction.amount
        }

        val categoryExpenses = categoryMap.map { (category, amount) ->
            CategoryExpense(name = category, amount = amount)
        }.sortedByDescending { it.amount }

        _analyticsData.value = AnalyticsData(
            totalIncome = currentIncome,
            totalExpense = currentExpense,
            incomeChangePercent = incomeChangePercent,
            expenseChangePercent = expenseChangePercent,
            monthlyData = last6MonthsData,
            categoryExpenses = categoryExpenses
        )
    }

    private fun getMonthFromDate(dateString: String): Int {
        return try {
            val monthAbbr = listOf(
                "Jan", "Feb", "Mar", "Apr", "May", "Jun",
                "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"
            )

            // Try to find month abbreviation in the date string
            for ((index, abbr) in monthAbbr.withIndex()) {
                if (dateString.contains(abbr, ignoreCase = true)) {
                    return index + 1
                }
            }

            // If no abbreviation found, try full month names
            val monthNames = listOf(
                "January", "February", "March", "April", "May", "June",
                "July", "August", "September", "October", "November", "December"
            )
            for ((index, fullMonth) in monthNames.withIndex()) {
                if (dateString.contains(fullMonth, ignoreCase = true)) {
                    return index + 1
                }
            }

            // Fallback: try to parse as yyyy-MM-dd format
            try {
                val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault())
                val date = dateFormat.parse(dateString) ?: return 0
                val calendar = Calendar.getInstance().apply { time = date }
                calendar.get(Calendar.MONTH) + 1
            } catch (_: Exception) {
                0
            }
        } catch (_: Exception) {
            0
        }
    }

    private fun getYearFromDate(dateString: String): Int {
        return try {
            // Try yyyy-MM-dd format first
            try {
                val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault())
                val date = dateFormat.parse(dateString) ?: return Calendar.getInstance().get(Calendar.YEAR)
                val calendar = Calendar.getInstance().apply { time = date }
                return calendar.get(Calendar.YEAR)
            } catch (_: Exception) {
                // If that fails, assume current year (most transactions are recent)
                Calendar.getInstance().get(Calendar.YEAR)
            }
        } catch (_: Exception) {
            Calendar.getInstance().get(Calendar.YEAR)
        }
    }

    private fun getDayFromDate(dateString: String): Int {
        return try {
            // Try yyyy-MM-dd format first
            try {
                val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault())
                val date = dateFormat.parse(dateString) ?: return 0
                val calendar = Calendar.getInstance().apply { time = date }
                return calendar.get(Calendar.DAY_OF_MONTH)
            } catch (_: Exception) {
                // Try to extract day from "d" or "dd" in various formats
                val dayRegex = Regex("""\b(\d{1,2})\b""")
                val match = dayRegex.find(dateString)
                match?.groupValues?.get(1)?.toIntOrNull() ?: 0
            }
        } catch (_: Exception) {
            0
        }
    }

    private fun getMonthName(monthNumber: Int): String {
        return when (monthNumber) {
            1 -> "January"
            2 -> "February"
            3 -> "March"
            4 -> "April"
            5 -> "May"
            6 -> "June"
            7 -> "July"
            8 -> "August"
            9 -> "September"
            10 -> "October"
            11 -> "November"
            12 -> "December"
            else -> ""
        }
    }
}

package com.example.spendroute.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.spendroute.data.model.CategoryExpense
import com.example.spendroute.data.model.Transaction
import com.example.spendroute.database.SpendRouteDatabase
import com.example.spendroute.repository.TransactionRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import java.text.SimpleDateFormat
import java.util.Calendar
import java.util.Locale

data class AnalyticsData(
    val totalIncome: Double = 0.0,
    val totalExpense: Double = 0.0,
    val incomeChangePercent: Float = 0f,
    val expenseChangePercent: Float = 0f,
    val monthlyData: List<MonthlyChartData> = emptyList(),
    val categoryExpenses: List<CategoryExpense> = emptyList()
)

data class MonthlyChartData(
    val month: String,
    val income: Double,
    val expense: Double
)

class AnalyticsViewModel(application: Application) : AndroidViewModel(application) {

    private val database = SpendRouteDatabase.getDatabase(application)
    private val repository = TransactionRepository(database.transactionDao())

    private val _analyticsData = MutableStateFlow<AnalyticsData>(AnalyticsData())
    val analyticsData: StateFlow<AnalyticsData> = _analyticsData.asStateFlow()

    private val _selectedPeriod = MutableStateFlow("Monthly")
    val selectedPeriod: StateFlow<String> = _selectedPeriod.asStateFlow()

    init {
        loadAnalyticsData()
    }

    fun selectPeriod(period: String) {
        _selectedPeriod.value = period
        loadAnalyticsData()
    }

    private fun loadAnalyticsData() {
        viewModelScope.launch {
            repository.getAllTransactions().collect { transactions ->
                when (_selectedPeriod.value) {
                    "Weekly" -> loadWeeklyData(transactions)
                    "Yearly" -> loadYearlyData(transactions)
                    else -> loadMonthlyData(transactions) // Monthly is default
                }
            }
        }
    }

    private fun loadMonthlyData(transactions: List<Transaction>) {
        // Get current month and last month
        val calendar = Calendar.getInstance()
        val currentMonth = calendar.get(Calendar.MONTH) + 1
        val currentYear = calendar.get(Calendar.YEAR)

        // Calculate current month data
        val currentMonthTransactions = transactions.filter { transaction ->
            val transactionMonth = getMonthFromDate(transaction.date)
            val transactionYear = getYearFromDate(transaction.date)
            transactionMonth == currentMonth && transactionYear == currentYear
        }

        val currentIncome = currentMonthTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val currentExpense = currentMonthTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate last month data for comparison
        val lastMonthDate = Calendar.getInstance().apply { add(Calendar.MONTH, -1) }
        val lastMonth = lastMonthDate.get(Calendar.MONTH) + 1
        val lastYear = lastMonthDate.get(Calendar.YEAR)

        val lastMonthTransactions = transactions.filter { transaction ->
            val transactionMonth = getMonthFromDate(transaction.date)
            val transactionYear = getYearFromDate(transaction.date)
            transactionMonth == lastMonth && transactionYear == lastYear
        }

        val lastIncome = lastMonthTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val lastExpense = lastMonthTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate percentage changes
        val incomeChangePercent = if (lastIncome > 0) {
            ((currentIncome - lastIncome) / lastIncome * 100).toFloat()
        } else {
            0f
        }

        val expenseChangePercent = if (lastExpense > 0) {
            ((currentExpense - lastExpense) / lastExpense * 100).toFloat()
        } else {
            0f
        }

        // Get last 6 months data for chart
        val last6MonthsData = mutableListOf<MonthlyChartData>()
        for (i in 5 downTo 0) {
            val monthCalendar = Calendar.getInstance().apply { add(Calendar.MONTH, -i) }
            val month = monthCalendar.get(Calendar.MONTH) + 1
            val year = monthCalendar.get(Calendar.YEAR)
            val monthName = getMonthName(month)

            val monthTransactions = transactions.filter { transaction ->
                val transactionMonth = getMonthFromDate(transaction.date)
                val transactionYear = getYearFromDate(transaction.date)
                transactionMonth == month && transactionYear == year
            }

            val monthIncome = monthTransactions.filter { it.isIncome }.sumOf { it.amount }
            val monthExpense = monthTransactions.filter { !it.isIncome }.sumOf { it.amount }

            last6MonthsData.add(
                MonthlyChartData(
                    month = monthName.take(3),
                    income = monthIncome,
                    expense = monthExpense
                )
            )
        }

        // Calculate category expenses
        val categoryMap = mutableMapOf<String, Double>()
        currentMonthTransactions.filter { !it.isIncome }.forEach { transaction ->
            val current = categoryMap[transaction.category] ?: 0.0
            categoryMap[transaction.category] = current + transaction.amount
        }

        val categoryExpenses = categoryMap.map { (category, amount) ->
            CategoryExpense(name = category, amount = amount)
        }.sortedByDescending { it.amount }

        _analyticsData.value = AnalyticsData(
            totalIncome = currentIncome,
            totalExpense = currentExpense,
            incomeChangePercent = incomeChangePercent,
            expenseChangePercent = expenseChangePercent,
            monthlyData = last6MonthsData,
            categoryExpenses = categoryExpenses
        )
    }

    private fun loadWeeklyData(transactions: List<Transaction>) {
        // Get current week start (6 days ago) and current date
        val calendar = Calendar.getInstance()
        val today = calendar.clone() as Calendar

        val weekStartCalendar = Calendar.getInstance()
        weekStartCalendar.add(Calendar.DAY_OF_YEAR, -6)

        val lastWeekStartCalendar = Calendar.getInstance()
        lastWeekStartCalendar.add(Calendar.DAY_OF_YEAR, -13)

        val lastWeekEndCalendar = Calendar.getInstance()
        lastWeekEndCalendar.add(Calendar.DAY_OF_YEAR, -7)

        // Helper function to check if date is between two dates (ignoring time)
        fun isDateInRange(dateString: String, startCalendar: Calendar, endCalendar: Calendar): Boolean {
            val month = getMonthFromDate(dateString)
            val year = getYearFromDate(dateString)
            val day = getDayFromDate(dateString)

            if (month == 0 || year == 0 || day == 0) return false

            val dateToCheck = Calendar.getInstance()
            dateToCheck.set(year, month - 1, day)

            val startDate = Calendar.getInstance()
            startDate.set(startCalendar.get(Calendar.YEAR), startCalendar.get(Calendar.MONTH), startCalendar.get(Calendar.DAY_OF_MONTH))

            val endDate = Calendar.getInstance()
            endDate.set(endCalendar.get(Calendar.YEAR), endCalendar.get(Calendar.MONTH), endCalendar.get(Calendar.DAY_OF_MONTH))

            return dateToCheck.timeInMillis >= startDate.timeInMillis && dateToCheck.timeInMillis <= endDate.timeInMillis
        }

        // Filter current week transactions
        val currentWeekTransactions = transactions.filter { transaction ->
            isDateInRange(transaction.date, weekStartCalendar, today)
        }

        val currentIncome = currentWeekTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val currentExpense = currentWeekTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Filter last week transactions
        val lastWeekTransactions = transactions.filter { transaction ->
            isDateInRange(transaction.date, lastWeekStartCalendar, lastWeekEndCalendar)
        }

        val lastIncome = lastWeekTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val lastExpense = lastWeekTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate percentage changes
        val incomeChangePercent = if (lastIncome > 0) {
            ((currentIncome - lastIncome) / lastIncome * 100).toFloat()
        } else {
            0f
        }

        val expenseChangePercent = if (lastExpense > 0) {
            ((currentExpense - lastExpense) / lastExpense * 100).toFloat()
        } else {
            0f
        }

        // Get last 6 weeks data for chart
        val last6WeeksData = mutableListOf<MonthlyChartData>()
        for (i in 5 downTo 0) {
            val weekCalendar = Calendar.getInstance()
            weekCalendar.add(Calendar.WEEK_OF_YEAR, -i)

            val weekStartDay = weekCalendar.clone() as Calendar
            weekStartDay.set(Calendar.DAY_OF_WEEK, Calendar.MONDAY)

            val weekEndDay = weekCalendar.clone() as Calendar
            weekEndDay.set(Calendar.DAY_OF_WEEK, Calendar.SUNDAY)

            val weekTransactions = transactions.filter { transaction ->
                isDateInRange(transaction.date, weekStartDay, weekEndDay)
            }

            val weekIncome = weekTransactions.filter { it.isIncome }.sumOf { it.amount }
            val weekExpense = weekTransactions.filter { !it.isIncome }.sumOf { it.amount }

            val weekLabel = "W${weekCalendar.get(Calendar.WEEK_OF_YEAR)}"
            last6WeeksData.add(
                MonthlyChartData(
                    month = weekLabel,
                    income = weekIncome,
                    expense = weekExpense
                )
            )
        }

        // Calculate category expenses for current week
        val categoryMap = mutableMapOf<String, Double>()
        currentWeekTransactions.filter { !it.isIncome }.forEach { transaction ->
            val current = categoryMap[transaction.category] ?: 0.0
            categoryMap[transaction.category] = current + transaction.amount
        }

        val categoryExpenses = categoryMap.map { (category, amount) ->
            CategoryExpense(name = category, amount = amount)
        }.sortedByDescending { it.amount }

        _analyticsData.value = AnalyticsData(
            totalIncome = currentIncome,
            totalExpense = currentExpense,
            incomeChangePercent = incomeChangePercent,
            expenseChangePercent = expenseChangePercent,
            monthlyData = last6WeeksData,
            categoryExpenses = categoryExpenses
        )
    }

    private fun loadYearlyData(transactions: List<Transaction>) {
        // Get current year and last year
        val calendar = Calendar.getInstance()
        val currentYear = calendar.get(Calendar.YEAR)
        val lastYear = currentYear - 1

        // Calculate current year data
        val currentYearTransactions = transactions.filter { transaction ->
            val transactionYear = getYearFromDate(transaction.date)
            transactionYear == currentYear
        }

        val currentIncome = currentYearTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val currentExpense = currentYearTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate last year data for comparison
        val lastYearTransactions = transactions.filter { transaction ->
            val transactionYear = getYearFromDate(transaction.date)
            transactionYear == lastYear
        }

        val lastIncome = lastYearTransactions
            .filter { it.isIncome }
            .sumOf { it.amount }

        val lastExpense = lastYearTransactions
            .filter { !it.isIncome }
            .sumOf { it.amount }

        // Calculate percentage changes
        val incomeChangePercent = if (lastIncome > 0) {
            ((currentIncome - lastIncome) / lastIncome * 100).toFloat()
        } else {
            0f
        }

        val expenseChangePercent = if (lastExpense > 0) {
            ((currentExpense - lastExpense) / lastExpense * 100).toFloat()
        } else {
            0f
        }

        // Get last 6 months data within current year for chart
        val last6MonthsData = mutableListOf<MonthlyChartData>()
        for (i in 5 downTo 0) {
            val monthCalendar = Calendar.getInstance().apply { add(Calendar.MONTH, -i) }
            val month = monthCalendar.get(Calendar.MONTH) + 1
            val year = monthCalendar.get(Calendar.YEAR)
            val monthName = getMonthName(month)

            val monthTransactions = transactions.filter { transaction ->
                val transactionMonth = getMonthFromDate(transaction.date)
                val transactionYear = getYearFromDate(transaction.date)
                transactionMonth == month && transactionYear == year
            }

            val monthIncome = monthTransactions.filter { it.isIncome }.sumOf { it.amount }
            val monthExpense = monthTransactions.filter { !it.isIncome }.sumOf { it.amount }

            last6MonthsData.add(
                MonthlyChartData(
                    month = monthName.take(3),
                    income = monthIncome,
                    expense = monthExpense
                )
            )
        }

        // Calculate category expenses for current year
        val categoryMap = mutableMapOf<String, Double>()
        currentYearTransactions.filter { !it.isIncome }.forEach { transaction ->
            val current = categoryMap[transaction.category] ?: 0.0
            categoryMap[transaction.category] = current + transaction.amount
        }

        val categoryExpenses = categoryMap.map { (category, amount) ->
            CategoryExpense(name = category, amount = amount)
        }.sortedByDescending { it.amount }

        _analyticsData.value = AnalyticsData(
            totalIncome = currentIncome,
            totalExpense = currentExpense,
            incomeChangePercent = incomeChangePercent,
            expenseChangePercent = expenseChangePercent,
            monthlyData = last6MonthsData,
            categoryExpenses = categoryExpenses
        )
    }

    private fun getMonthFromDate(dateString: String): Int {
        return try {
            val monthAbbr = listOf(
                "Jan", "Feb", "Mar", "Apr", "May", "Jun",
                "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"
            )

            // Try to find month abbreviation in the date string
            for ((index, abbr) in monthAbbr.withIndex()) {
                if (dateString.contains(abbr, ignoreCase = true)) {
                    return index + 1
                }
            }

            // If no abbreviation found, try full month names
            val monthNames = listOf(
                "January", "February", "March", "April", "May", "June",
                "July", "August", "September", "October", "November", "December"
            )
            for ((index, fullMonth) in monthNames.withIndex()) {
                if (dateString.contains(fullMonth, ignoreCase = true)) {
                    return index + 1
                }
            }

            // Fallback: try to parse as yyyy-MM-dd format
            try {
                val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault())
                val date = dateFormat.parse(dateString) ?: return 0
                val calendar = Calendar.getInstance().apply { time = date }
                calendar.get(Calendar.MONTH) + 1
            } catch (_: Exception) {
                0
            }
        } catch (_: Exception) {
            0
        }
    }

    private fun getYearFromDate(dateString: String): Int {
        return try {
            // Try yyyy-MM-dd format first
            try {
                val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault())
                val date = dateFormat.parse(dateString) ?: return Calendar.getInstance().get(Calendar.YEAR)
                val calendar = Calendar.getInstance().apply { time = date }
                return calendar.get(Calendar.YEAR)
            } catch (_: Exception) {
                // If that fails, assume current year (most transactions are recent)
                Calendar.getInstance().get(Calendar.YEAR)
            }
        } catch (_: Exception) {
            Calendar.getInstance().get(Calendar.YEAR)
        }
    }

    private fun getDayFromDate(dateString: String): Int {
        return try {
            // Try yyyy-MM-dd format first
            try {
                val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault())
                val date = dateFormat.parse(dateString) ?: return 0
                val calendar = Calendar.getInstance().apply { time = date }
                return calendar.get(Calendar.DAY_OF_MONTH)
            } catch (_: Exception) {
                // Try other common formats
                val formats = listOf(
                    SimpleDateFormat("MMM d, yyyy", Locale.getDefault()),
                    SimpleDateFormat("dd/MM/yyyy", Locale.getDefault()),
                    SimpleDateFormat("d MMM yyyy", Locale.getDefault()),
                    SimpleDateFormat("MMMM d, yyyy", Locale.getDefault())
                )

                for (format in formats) {
                    try {
                        val date = format.parse(dateString) ?: continue
                        val calendar = Calendar.getInstance().apply { time = date }
                        return calendar.get(Calendar.DAY_OF_MONTH)
                    } catch (_: Exception) {
                        continue
                    }
                }
                0
            }
        } catch (_: Exception) {
            0
        }
    }

    private fun getMonthName(monthNumber: Int): String {
        return when (monthNumber) {
            1 -> "January"
            2 -> "February"
            3 -> "March"
            4 -> "April"
            5 -> "May"
            6 -> "June"
            7 -> "July"
            8 -> "August"
            9 -> "September"
            10 -> "October"
            11 -> "November"
            12 -> "December"
            else -> ""
        }
    }
}

