    val textColor = if (isLightBackground) Color.Black else Color.White
    val subtitleColor = if (isLightBackground) Color(0xFF9E9E9E) else Color(0xFFB8B3E5)

    if (isSimpleMode) {
        // ...existing code...
        Box(
            modifier = modifier
                .fillMaxWidth()
                .background(headerBackgroundColor)
