                        color = textColor
                    )
                    Text(
                        text = name,
                        style = if (boldGreeting) LocalTypography.current.bodyMediumRegular else LocalTypography.current.headingSmallSemibold,
                        color = if (boldGreeting) subtitleColor else textColor
                    )
