import com.example.spendroute.data.model.BalanceInfo
import com.example.spendroute.data.model.CategoryExpense
import com.example.spendroute.data.model.Transaction
import com.example.spendroute.data.UserPreferences
import com.example.spendroute.ui.components.BalanceCard
import com.example.spendroute.ui.components.CategoryPills
import com.example.spendroute.ui.components.GreetingHeader
import com.example.spendroute.ui.components.RecentTransactions
import com.example.spendroute.ui.theme.SpendRouteTheme
import com.example.spendroute.viewmodel.HomeViewModel
import com.example.spendroute.viewmodel.factory.HomeViewModelFactory

@Composable
fun HomeScreen(
    modifier: Modifier = Modifier,
    onNavigateToTransactions: () -> Unit = {},
    onNavigateToAddEdit: (Transaction?) -> Unit = {},
    viewModel: HomeViewModel = viewModel(
        factory = HomeViewModelFactory(
            LocalContext.current.applicationContext as android.app.Application
        )
    )
) {
    val balanceInfo = viewModel.balanceInfo.collectAsState()
    val recentTransactions = viewModel.recentTransactions.collectAsState()
    val categoryExpenses = viewModel.categoryExpenses.collectAsState()

    // Get user name from preferences
    val context = LocalContext.current
    val userPreferences = UserPreferences(context)
    val userName = userPreferences.getUserName()
    val userInitials = userPreferences.getUserInitials()

    // Track selected month
    val selectedMonth = remember { mutableStateOf("") }

    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFFF8F7FC))
    ) {
        // Fixed Greeting Header - stays at top while scrolling
        GreetingHeader(
            name = userName,
            initials = userInitials,
            avatarBackgroundColor = Color(0xFF7C6FD4),
        )

        // Scrollable content
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFFF8F7FC))
        ) {
            // Balance Card - fetched from database
            item {
                if (balanceInfo.value != null) {
                    BalanceCard(
                        balanceInfo = balanceInfo.value!!,
                        onMonthSelected = { month ->
                            selectedMonth.value = month
                            viewModel.fetchDataForMonth(month)
                        }
                    )
                } else {
                    BalanceCard(
                        balanceInfo = BalanceInfo(
                            month = "",  // Empty - will use current month dynamically
                            totalBalance = 0.0,
                            income = 0.0,
                            expense = 0.0,
                            budget = 25000.0,
                            usedPercentage = 0f
                        ),
                        onMonthSelected = { month ->
                            selectedMonth.value = month
                            viewModel.fetchDataForMonth(month)
                        }
                    )
                }
            }

            // Category Pills - fetched from database
            item {
                CategoryPills(
                    categories = categoryExpenses.value.map { (category, amount) ->
                        CategoryExpense(name = category, amount = amount)
                    }
                )
            }

            // Recent Transactions
            item {
                RecentTransactions(
                    transactions = recentTransactions.value,
                    onSeeAllClick = {
                        onNavigateToTransactions()
                    },
                    onEditTransaction = { transaction ->
                        onNavigateToAddEdit(transaction)
                    },
                    onDeleteTransaction = { transactionId ->
                        viewModel.deleteTransaction(transactionId)
                    }
                )
            }
        }
    }
}

