package com.example.spendroute.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.spendroute.data.model.BalanceInfo
import com.example.spendroute.data.model.Transaction
import com.example.spendroute.database.SpendRouteDatabase
import com.example.spendroute.repository.TransactionRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

class HomeViewModel(application: Application) : AndroidViewModel(application) {

    private val database = SpendRouteDatabase.getDatabase(application)
    private val repository = TransactionRepository(database.transactionDao())

    private val _balanceInfo = MutableStateFlow<BalanceInfo?>(null)
    val balanceInfo: StateFlow<BalanceInfo?> = _balanceInfo.asStateFlow()

    private val _recentTransactions = MutableStateFlow<List<Transaction>>(emptyList())
    val recentTransactions: StateFlow<List<Transaction>> = _recentTransactions.asStateFlow()

    private val _categoryExpenses = MutableStateFlow<Map<String, Double>>(emptyMap())
    val categoryExpenses: StateFlow<Map<String, Double>> = _categoryExpenses.asStateFlow()

    init {
        loadData()
    }

    private fun loadData() {
        viewModelScope.launch {
            repository.getAllTransactions().collect { transactions ->
                // Calculate balance info
                val income = transactions.filter { it.isIncome }.sumOf { it.amount }
                val expense = transactions.filter { !it.isIncome }.sumOf { it.amount }
                val balance = income - expense

                _balanceInfo.value = BalanceInfo(
                    month = "APRIL",
                    totalBalance = balance,
                    income = income,
                    expense = expense,
                    budget = 25000.0, // TODO: Get from settings
                    usedPercentage = if (expense > 0 && balance > 0) (expense / 25000f * 100).toFloat() else 0f
                )

                // Get recent transactions (last 5)
                _recentTransactions.value = transactions.take(5)

                // Calculate category expenses
                val categoryMap = mutableMapOf<String, Double>()
                transactions.filter { !it.isIncome }.forEach { transaction ->
                    val current = categoryMap[transaction.category] ?: 0.0
                    categoryMap[transaction.category] = current + transaction.amount
                }
                _categoryExpenses.value = categoryMap
            }
        }
    }

    fun fetchDataForMonth(month: String) {
        viewModelScope.launch {
            repository.getAllTransactions().collect { transactions ->
                // Filter transactions by month (if applicable)
                // For now, we'll show all transactions since we don't have month filtering in database
                val income = transactions.filter { it.isIncome }.sumOf { it.amount }
                val expense = transactions.filter { !it.isIncome }.sumOf { it.amount }
                val balance = income - expense

                _balanceInfo.value = BalanceInfo(
                    month = month,
                    totalBalance = balance,
                    income = income,
                    expense = expense,
                    budget = 25000.0,
                    usedPercentage = if (expense > 0 && balance > 0) (expense / 25000f * 100).toFloat() else 0f
                )

                // Get recent transactions
                _recentTransactions.value = transactions.take(5)

                // Calculate category expenses
                val expenses = transactions.filter { !it.isIncome }
                _categoryExpenses.value = expenses.groupBy { it.category }
                    .mapValues { (_, items) -> items.sumOf { it.amount } }
            }
        }
    }
}

package com.example.spendroute.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.spendroute.data.model.BalanceInfo
import com.example.spendroute.data.model.Transaction
import com.example.spendroute.database.SpendRouteDatabase
import com.example.spendroute.repository.TransactionRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

class HomeViewModel(application: Application) : AndroidViewModel(application) {

    private val database = SpendRouteDatabase.getDatabase(application)
    private val repository = TransactionRepository(database.transactionDao())

    private val _balanceInfo = MutableStateFlow<BalanceInfo?>(null)
    val balanceInfo: StateFlow<BalanceInfo?> = _balanceInfo.asStateFlow()

    private val _recentTransactions = MutableStateFlow<List<Transaction>>(emptyList())
    val recentTransactions: StateFlow<List<Transaction>> = _recentTransactions.asStateFlow()

    private val _categoryExpenses = MutableStateFlow<Map<String, Double>>(emptyMap())
    val categoryExpenses: StateFlow<Map<String, Double>> = _categoryExpenses.asStateFlow()

    init {
        loadData()
    }

    private fun loadData() {
        viewModelScope.launch {
            repository.getAllTransactions().collect { transactions ->
                // Calculate balance info
                val income = transactions.filter { it.isIncome }.sumOf { it.amount }
                val expense = transactions.filter { !it.isIncome }.sumOf { it.amount }
                val balance = income - expense

                _balanceInfo.value = BalanceInfo(
                    month = "APRIL",
                    totalBalance = balance,
                    income = income,
                    expense = expense,
                    budget = 25000.0, // TODO: Get from settings
                    usedPercentage = if (expense > 0 && balance > 0) (expense / 25000f * 100).toFloat() else 0f
                )

                // Get recent transactions (last 5)
                _recentTransactions.value = transactions.take(5)

                // Calculate category expenses
                val categoryMap = mutableMapOf<String, Double>()
                transactions.filter { !it.isIncome }.forEach { transaction ->
                    val current = categoryMap[transaction.category] ?: 0.0
                    categoryMap[transaction.category] = current + transaction.amount
                }
                _categoryExpenses.value = categoryMap
            }
        }
    }

    fun fetchDataForMonth(month: String) {
        viewModelScope.launch {
            repository.getAllTransactions().collect { transactions ->
                // Convert month name to month number (JANUARY = 1, etc.)
                val monthNumber = getMonthNumber(month)

                // Filter transactions by the selected month
                val filteredTransactions = transactions.filter { transaction ->
                    val transactionMonth = getMonthFromDate(transaction.date)
                    transactionMonth == monthNumber
                }

                // Calculate balance for selected month only
                val income = filteredTransactions.filter { it.isIncome }.sumOf { it.amount }
                val expense = filteredTransactions.filter { !it.isIncome }.sumOf { it.amount }
                val balance = income - expense

                _balanceInfo.value = BalanceInfo(
                    month = month,
                    totalBalance = balance,
                    income = income,
                    expense = expense,
                    budget = 25000.0,
                    usedPercentage = if (expense > 0 && balance > 0) (expense / 25000f * 100).toFloat() else 0f
                )

                // Get recent transactions from filtered list
                _recentTransactions.value = filteredTransactions.take(5)

                // Calculate category expenses from filtered transactions
                val expenses = filteredTransactions.filter { !it.isIncome }
                _categoryExpenses.value = expenses.groupBy { it.category }
                    .mapValues { (_, items) -> items.sumOf { it.amount } }
            }
        }
    }

    // Helper function to convert month name to number
    private fun getMonthNumber(monthName: String): Int {
        val months = listOf(
            "JANUARY", "FEBRUARY", "MARCH", "APRIL", "MAY", "JUNE",
            "JULY", "AUGUST", "SEPTEMBER", "OCTOBER", "NOVEMBER", "DECEMBER"
        )
        return months.indexOf(monthName) + 1
    }

    // Helper function to extract month number from date string (assuming format "MMM d, yyyy" or similar)
    private fun getMonthFromDate(dateString: String): Int {
        return try {
            val monthNames = listOf(
                "JANUARY", "FEBRUARY", "MARCH", "APRIL", "MAY", "JUNE",
                "JULY", "AUGUST", "SEPTEMBER", "OCTOBER", "NOVEMBER", "DECEMBER"
            )
            val monthAbbr = listOf(
                "Jan", "Feb", "Mar", "Apr", "May", "Jun",
                "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"
            )

            // Try to find month abbreviation or full name in the date string
            for ((index, abbr) in monthAbbr.withIndex()) {
                if (dateString.contains(abbr, ignoreCase = true)) {
                    return index + 1
                }
            }

            for ((index, fullMonth) in monthNames.withIndex()) {
                if (dateString.contains(fullMonth, ignoreCase = true)) {
                    return index + 1
                }
            }

            0 // No month found
        } catch (e: Exception) {
            0
        }
    }
}

