package com.example.spendroute.database.entity
import androidx.room.Entity import androidx.room.PrimaryKey
@Entity(tableName = "transactions") data class TransactionEntity( @PrimaryKey(autoGenerate = true) val id: Int = 0, val title: String, val category: String, val amount: Double, val date: String, val time: String, val isIncome: Boolean, val timestamp: Long = System.currentTimeMillis() )

package com.example.spendroute.repository

import com.example.spendroute.database.dao.TransactionDao
import com.example.spendroute.database.entity.TransactionEntity
import com.example.spendroute.data.model.Transaction
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

class TransactionRepository(private val transactionDao: TransactionDao) {

    // Get all transactions
    fun getAllTransactions(): Flow<List<Transaction>> {
        return transactionDao.getAllTransactions().map { entities ->
            entities.map { it.toTransaction() }
        }
    }

    // Get income transactions only
    fun getIncomeTransactions(): Flow<List<Transaction>> {
        return transactionDao.getIncomeTransactions().map { entities ->
            entities.map { it.toTransaction() }
        }
    }

    // Get expense transactions only
    fun getExpenseTransactions(): Flow<List<Transaction>> {
        return transactionDao.getExpenseTransactions().map { entities ->
            entities.map { it.toTransaction() }
        }
    }

    // Insert transaction
    suspend fun insertTransaction(transaction: Transaction) {
        transactionDao.insertTransaction(transaction.toEntity())
    }

    // Update transaction
    suspend fun updateTransaction(transaction: Transaction) {
        transactionDao.updateTransaction(transaction.toEntity())
    }

    // Delete transaction
    suspend fun deleteTransaction(transaction: Transaction) {
        transactionDao.deleteTransaction(transaction.toEntity())
    }

    // Delete all transactions
    suspend fun deleteAllTransactions() {
        transactionDao.deleteAllTransactions()
    }

    // Helper: Entity to Model
    private fun TransactionEntity.toTransaction(): Transaction {
        return Transaction(
            id = this.id.toString(),
            title = this.title,
            category = this.category,
            amount = this.amount,
            date = this.date,
            time = this.time,
            isIncome = this.isIncome
        )
    }

    // Helper: Model to Entity
    private fun Transaction.toEntity(): TransactionEntity {
        return TransactionEntity(
            id = this.id.toIntOrNull() ?: 0,
            title = this.title,
            category = this.category,
            amount = this.amount,
            date = this.date,
            time = this.time,
            isIncome = this.isIncome
        )
    }
}

package com.example.spendroute.repository

import com.example.spendroute.database.dao.TransactionDao
import com.example.spendroute.database.entity.TransactionEntity
import com.example.spendroute.data.model.Transaction
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

class TransactionRepository(private val transactionDao: TransactionDao) {

    // Get all transactions
    fun getAllTransactions(): Flow<List<Transaction>> {
        return transactionDao.getAllTransactions().map { entities ->
            entities.map { it.toTransaction() }
        }
    }

    // Get income transactions only
    fun getIncomeTransactions(): Flow<List<Transaction>> {
        return transactionDao.getIncomeTransactions().map { entities ->
            entities.map { it.toTransaction() }
        }
    }

    // Get expense transactions only
    fun getExpenseTransactions(): Flow<List<Transaction>> {
        return transactionDao.getExpenseTransactions().map { entities ->
            entities.map { it.toTransaction() }
        }
    }

    // Insert transaction
    suspend fun insertTransaction(transaction: Transaction) {
        transactionDao.insertTransaction(transaction.toEntity())
    }

    // Update transaction
    suspend fun updateTransaction(transaction: Transaction) {
        transactionDao.updateTransaction(transaction.toEntity())
    }

    // Delete transaction by ID
    suspend fun deleteTransaction(transactionId: String) {
        transactionDao.deleteTransactionById(transactionId.toIntOrNull() ?: return)
    }

    // Delete transaction object
    suspend fun deleteTransactionObject(transaction: Transaction) {
        transactionDao.deleteTransaction(transaction.toEntity())
    }

    // Delete all transactions
    suspend fun deleteAllTransactions() {
        transactionDao.deleteAllTransactions()
    }

    // Helper: Entity to Model
    private fun TransactionEntity.toTransaction(): Transaction {
        return Transaction(
            id = this.id.toString(),
            title = this.title,
            category = this.category,
            amount = this.amount,
            date = this.date,
            time = this.time,
            isIncome = this.isIncome
        )
    }

    // Helper: Model to Entity
    private fun Transaction.toEntity(): TransactionEntity {
        return TransactionEntity(
            id = this.id.toIntOrNull() ?: 0,
            title = this.title,
            category = this.category,
            amount = this.amount,
            date = this.date,
            time = this.time,
            isIncome = this.isIncome
        )
    }
}

