import com.example.spendroute.viewmodel.factory.TransactionsViewModelFactory
import com.example.spendroute.data.model.Transaction

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun TransactionsScreen(
    modifier: Modifier = Modifier,
    viewModel: TransactionsViewModel = viewModel(
        factory = TransactionsViewModelFactory(
            LocalContext.current.applicationContext as android.app.Application
        )
    )
) {
    val searchQuery = viewModel.searchQuery.collectAsState()
    val selectedFilter = viewModel.filterType.collectAsState()
    val filteredTransactions = viewModel.filteredTransactions.collectAsState()

    Column(
        modifier = modifier
            .fillMaxSize()
            .background(Color(0xFFF8F7FC))
    ) {
        // Fixed Purple Header - stays at top while scrolling
        GreetingHeader(
            title = "Transactions",
            subtitle = "Income & expenses in one place",
            //headerBackgroundColor = Color(0xFF5B4B9B),
            showAvatar = false
        )

        // Scrollable content
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .background(Color(0xFFF8F7FC))
        ) {
            // Search Bar - Using Material 3 SearchBar
            item {
                SearchBar(
                    query = searchQuery.value,
                    onQueryChange = { viewModel.setSearchQuery(it) },
                    onSearch = {},
                    active = false,
                    onActiveChange = {},
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(horizontal = 16.dp, vertical = 8.dp),
                    placeholder = {
                        Text(
                            text = "Search transactions...",
                            style = LocalTypography.current.bodyMediumRegular,
                            color = Color.Gray
                        )
                    },
                    leadingIcon = {
                        Icon(
                            imageVector = Icons.Default.Search,
                            contentDescription = "Search",
                            tint = Color.Gray
                        )
                    },
                    windowInsets = WindowInsets(0.dp)
                ) {}
            }

        // Filter Pills - Using FilterChip from Material 3
        item {
            val filterButtons = listOf(
                Pair("All", FilterType.ALL),
                Pair("Income", FilterType.INCOME),
                Pair("Expense", FilterType.EXPENSE)
            )

            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 12.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                filterButtons.forEach { (label, filterType) ->
                    FilterChip(
                        selected = selectedFilter.value == filterType,
                        onClick = { viewModel.setFilterType(filterType) },
                        label = {
                            Text(
                                text = label,
                                textAlign = TextAlign.Center,
                                modifier = Modifier.fillMaxWidth()
                            )
                        },
                        modifier = Modifier.weight(1f),
                        colors = FilterChipDefaults.filterChipColors(
                            containerColor = Color(0xFFF5F5F5),
                            selectedContainerColor = Color(0xFF5B4B9B),
                            selectedLabelColor = Color.White,
                            labelColor = Color(0xFF5B4B9B)
                        )
                    )
                }
            }
        }

        // Transaction List - Using RecentTransactions Component
        item {
            if (filteredTransactions.value.isNotEmpty()) {
                RecentTransactions(
                    transactions = filteredTransactions.value,
                    onSeeAllClick = {}
                )
            }
        }

        // Empty State
        if (filteredTransactions.value.isEmpty()) {
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(32.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = "No transactions found",
                        style = LocalTypography.current.bodyMediumPrimary,
                        color = Color(0xFF9E9E9E)
                    )
                }
            }
        }

        // Bottom spacing for navigation bar
        item {
            Box(modifier = Modifier.height(80.dp))
        }
    }
    }
}

