package com.example.spendroute.viewmodel

import androidx.lifecycle.ViewModel
import com.example.spendroute.data.model.Transaction
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow

enum class FilterType {
    ALL, INCOME, EXPENSE
}

class TransactionsViewModel : ViewModel() {

    private val _filterType = MutableStateFlow(FilterType.ALL)
    val filterType: StateFlow<FilterType> = _filterType.asStateFlow()

    private val _searchQuery = MutableStateFlow("")
    val searchQuery: StateFlow<String> = _searchQuery.asStateFlow()

    private val _allTransactions = MutableStateFlow<List<Transaction>>(emptyList())
    val allTransactions: StateFlow<List<Transaction>> = _allTransactions.asStateFlow()

    private val _filteredTransactions = MutableStateFlow<List<Transaction>>(emptyList())
    val filteredTransactions: StateFlow<List<Transaction>> = _filteredTransactions.asStateFlow()

    fun addTransaction(transaction: Transaction) {
        val currentList = _allTransactions.value.toMutableList()
        currentList.add(0, transaction)
        _allTransactions.value = currentList
        applyFiltersAndSearch()
    }

    fun setFilterType(filter: FilterType) {
        _filterType.value = filter
        applyFiltersAndSearch()
    }

    fun setSearchQuery(query: String) {
        _searchQuery.value = query
        applyFiltersAndSearch()
    }

    private fun applyFiltersAndSearch() {
        var transactions = _allTransactions.value

        // Apply filter
        transactions = when (_filterType.value) {
            FilterType.ALL -> transactions
            FilterType.INCOME -> transactions.filter { it.isIncome }
            FilterType.EXPENSE -> transactions.filter { !it.isIncome }
        }

        // Apply search
        if (_searchQuery.value.isNotEmpty()) {
            transactions = transactions.filter { transaction ->
                transaction.title.contains(_searchQuery.value, ignoreCase = true) ||
                        transaction.category.contains(_searchQuery.value, ignoreCase = true)
            }
        }

        _filteredTransactions.value = transactions
    }

    fun deleteTransaction(transaction: Transaction) {
        val currentList = _allTransactions.value.toMutableList()
        currentList.removeIf { it.id == transaction.id }
        _allTransactions.value = currentList
        applyFiltersAndSearch()
    }

    fun deleteAllTransactions() {
        _allTransactions.value = emptyList()
        _filteredTransactions.value = emptyList()
    }
}

package com.example.spendroute.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.spendroute.data.model.Transaction
import com.example.spendroute.database.SpendRouteDatabase
import com.example.spendroute.repository.TransactionRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

enum class FilterType {
    ALL, INCOME, EXPENSE
}

class TransactionsViewModel(application: Application) : AndroidViewModel(application) {

    private val database = SpendRouteDatabase.getDatabase(application)
    private val repository = TransactionRepository(database.transactionDao())

    private val _filterType = MutableStateFlow(FilterType.ALL)
    val filterType: StateFlow<FilterType> = _filterType.asStateFlow()

    private val _searchQuery = MutableStateFlow("")
    val searchQuery: StateFlow<String> = _searchQuery.asStateFlow()

    private val _allTransactions = MutableStateFlow<List<Transaction>>(emptyList())
    val allTransactions: StateFlow<List<Transaction>> = _allTransactions.asStateFlow()

    private val _filteredTransactions = MutableStateFlow<List<Transaction>>(emptyList())
    val filteredTransactions: StateFlow<List<Transaction>> = _filteredTransactions.asStateFlow()

    init {
        loadTransactions()
    }

    private fun loadTransactions() {
        viewModelScope.launch {
            repository.getAllTransactions().collect { transactions ->
                _allTransactions.value = transactions
                applyFiltersAndSearch()
            }
        }
    }

    fun addTransaction(transaction: Transaction) {
        viewModelScope.launch {
            repository.insertTransaction(transaction)
        }
    }

    fun setFilterType(filter: FilterType) {
        _filterType.value = filter
        applyFiltersAndSearch()
    }

    fun setSearchQuery(query: String) {
        _searchQuery.value = query
        applyFiltersAndSearch()
    }

    private fun applyFiltersAndSearch() {
        var transactions = _allTransactions.value

        // Apply filter
        transactions = when (_filterType.value) {
            FilterType.ALL -> transactions
            FilterType.INCOME -> transactions.filter { it.isIncome }
            FilterType.EXPENSE -> transactions.filter { !it.isIncome }
        }

        // Apply search
        if (_searchQuery.value.isNotEmpty()) {
            transactions = transactions.filter { transaction ->
                transaction.title.contains(_searchQuery.value, ignoreCase = true) ||
                        transaction.category.contains(_searchQuery.value, ignoreCase = true)
            }
        }

        _filteredTransactions.value = transactions
    }

    fun deleteTransaction(transaction: Transaction) {
        viewModelScope.launch {
            repository.deleteTransaction(transaction)
        }
    }

    fun deleteAllTransactions() {
        viewModelScope.launch {
            repository.deleteAllTransactions()
        }
    }
}

package com.example.spendroute.data

import android.content.Context
import android.content.SharedPreferences

class UserPreferences(context: Context) {

    private val sharedPreferences: SharedPreferences = 
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    companion object {
        private const val PREFS_NAME = "spendroute_prefs"
        private const val KEY_USER_NAME = "user_name"
        private const val KEY_IS_ONBOARDING_COMPLETED = "is_onboarding_completed"
    }

    // Save user name
    fun saveUserName(name: String) {
        sharedPreferences.edit().putString(KEY_USER_NAME, name).apply()
    }

    // Get user name
    fun getUserName(): String {
        return sharedPreferences.getString(KEY_USER_NAME, "") ?: ""
    }

    // Get user initials from name
    fun getUserInitials(): String {
        val name = getUserName()
        if (name.isEmpty()) return ""

        val parts = name.trim().split(" ")
        return when {
            parts.size >= 2 -> "${parts[0].first().uppercaseChar()}${parts[1].first().uppercaseChar()}"
            parts.size == 1 -> parts[0].take(2).uppercase()
            else -> ""
        }
    }

    // Mark onboarding as completed
    fun setOnboardingCompleted(completed: Boolean) {
        sharedPreferences.edit().putBoolean(KEY_IS_ONBOARDING_COMPLETED, completed).apply()
    }

    // Check if onboarding is completed
    fun isOnboardingCompleted(): Boolean {
        return sharedPreferences.getBoolean(KEY_IS_ONBOARDING_COMPLETED, false)
    }
}

package com.example.spendroute.data

import android.content.Context
import android.content.SharedPreferences

class UserPreferences(context: Context) {

    private val sharedPreferences: SharedPreferences = 
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    companion object {
        private const val PREFS_NAME = "spendroute_prefs"
        private const val KEY_USER_NAME = "user_name"
        private const val KEY_IS_ONBOARDING_COMPLETED = "is_onboarding_completed"
        private const val KEY_ACCOUNT_CREATED_DATE = "account_created_date"
    }

    // Save user name
    fun saveUserName(name: String) {
        sharedPreferences.edit().putString(KEY_USER_NAME, name).apply()
        // Also save the account creation date when user name is first set
        if (!isOnboardingCompleted()) {
            saveAccountCreatedDate()
        }
    }

    // Save account creation date
    private fun saveAccountCreatedDate() {
        val currentDate = java.text.SimpleDateFormat("MMMM yyyy", java.util.Locale.getDefault())
            .format(java.util.Date())
        sharedPreferences.edit().putString(KEY_ACCOUNT_CREATED_DATE, currentDate).apply()
    }

    // Get account creation date
    fun getAccountCreatedDate(): String {
        return sharedPreferences.getString(KEY_ACCOUNT_CREATED_DATE, "April 2026") ?: "April 2026"
    }

    // Get user name
    fun getUserName(): String {
        return sharedPreferences.getString(KEY_USER_NAME, "") ?: ""
    }

    // Get user initials from name
    fun getUserInitials(): String {
        val name = getUserName()
        if (name.isEmpty()) return ""

        val parts = name.trim().split(" ")
        return when {
            parts.size >= 2 -> "${parts[0].first().uppercaseChar()}${parts[1].first().uppercaseChar()}"
            parts.size == 1 -> parts[0].take(2).uppercase()
            else -> ""
        }
    }

    // Mark onboarding as completed
    fun setOnboardingCompleted(completed: Boolean) {
        sharedPreferences.edit().putBoolean(KEY_IS_ONBOARDING_COMPLETED, completed).apply()
    }

    // Check if onboarding is completed
    fun isOnboardingCompleted(): Boolean {
        return sharedPreferences.getBoolean(KEY_IS_ONBOARDING_COMPLETED, false)
    }
}

